impl Feature {
    /// Returns whether all of the given browser targets support this feature
    /// natively, without fallback.
    pub fn is_compatible(self, browsers: &Browsers) -> bool {
        let Some(min) = &MIN_VERSIONS[self as usize] else {
            return false;
        };
        macro_rules! check {
            ($field:ident) => {
                if let Some(version) = browsers.$field {
                    if min.$field == UNSUPPORTED || version < min.$field {
                        return false;
                    }
                }
            };
        }
        check!(android);
        check!(chrome);
        check!(edge);
        check!(firefox);
        check!(ie);
        check!(ios_saf);
        check!(opera);
        check!(safari);
        check!(samsung);
        true
    }

    /// Returns whether *any* of the given browser targets supports this
    /// feature natively.
    pub fn is_partially_compatible(self, targets: &Browsers) -> bool {
        let Some(min) = &MIN_VERSIONS[self as usize] else {
            return false;
        };
        macro_rules! check {
            ($field:ident) => {
                if let Some(version) = targets.$field {
                    if min.$field != UNSUPPORTED && version >= min.$field {
                        return true;
                    }
                }
            };
        }
        check!(android);
        check!(chrome);
        check!(edge);
        check!(firefox);
        check!(ie);
        check!(ios_saf);
        check!(opera);
        check!(safari);
        check!(samsung);
        false
    }
}
